#graphql
  query StandardLinkedMetafieldTaxonomyValues {
    materialCategories: taxonomy {
      categories(first: 10, search: "chair") {
        nodes {
          id
          name
          attributes(first: 50) {
            nodes {
              __typename
              ... on TaxonomyChoiceListAttribute {
                id
                name
                values(first: 5) { nodes { id name } }
              }
            }
          }
        }
      }
    }
    colorCategories: taxonomy {
      categories(first: 10, search: "shirt") {
        nodes {
          id
          name
          attributes(first: 50) {
            nodes {
              __typename
              ... on TaxonomyChoiceListAttribute {
                id
                name
                values(first: 5) { nodes { id name } }
              }
            }
          }
        }
      }
    }
  }

#graphql
  query StandardLinkedMetafieldConstraintIntersection {
    material: metafieldDefinition(
      identifier: { ownerType: PRODUCT, namespace: "shopify", key: "material" }
    ) {
      constraints { values(first: 250) { nodes { value } } }
    }
    colorPattern: metafieldDefinition(
      identifier: { ownerType: PRODUCT, namespace: "shopify", key: "color-pattern" }
    ) {
      constraints { values(first: 250) { nodes { value } } }
    }
  }

mutation StandardLinkedMetafieldDefinitionSetup {
  material: standardMetafieldDefinitionEnable(ownerType: PRODUCT, namespace: "shopify", key: "material") {
    createdDefinition {
      id
      namespace
      key
      ownerType
      name
      description
      type {
        name
        category
      }
      validations {
        name
        value
      }
      constraints {
        key
        values(first: 5) {
          nodes {
            value
          }
        }
      }
      access {
        admin
        storefront
        customerAccount
      }
    }
    userErrors {
      field
      message
      code
    }
  }
  colorPattern: standardMetafieldDefinitionEnable(
    ownerType: PRODUCT
    namespace: "shopify"
    key: "color-pattern"
  ) {
    createdDefinition {
      id
      namespace
      key
      ownerType
      name
      description
      type {
        name
        category
      }
      validations {
        name
        value
      }
      constraints {
        key
        values(first: 5) {
          nodes {
            value
          }
        }
      }
      access {
        admin
        storefront
        customerAccount
      }
    }
    userErrors {
      field
      message
      code
    }
  }
}

mutation StandardLinkedMetafieldProductCreate($product: ProductCreateInput!) {
  productCreate(product: $product) {
    product {
      id
      title
    }
    userErrors {
      field
      message
    }
  }
}

query StandardLinkedMetafieldDefinitionRead($materialId: ID!, $colorPatternId: ID!) {
  materialById: metaobjectDefinition(id: $materialId) {
    id
    type
    name
    displayNameKey
  }
  materialByType: metaobjectDefinitionByType(type: "shopify--material") {
    id
    type
    name
    displayNameKey
  }
  materialNode: node(id: $materialId) {
    __typename
    ... on MetaobjectDefinition {
      id
      type
      name
      displayNameKey
    }
  }
  colorPatternById: metaobjectDefinition(id: $colorPatternId) {
    id
    type
    name
    displayNameKey
  }
  colorPatternByType: metaobjectDefinitionByType(type: "shopify--color-pattern") {
    id
    type
    name
    displayNameKey
  }
  colorPatternNode: node(id: $colorPatternId) {
    __typename
    ... on MetaobjectDefinition {
      id
      type
      name
      displayNameKey
    }
  }
}

mutation StandardLinkedMetafieldValuesCreate(
  $material: MetaobjectCreateInput!
  $colorPattern: MetaobjectCreateInput!
) {
  material: metaobjectCreate(metaobject: $material) {
    metaobject {
      id
      type
      handle
      displayName
      definition {
        id
        type
      }
    }
    userErrors {
      field
      message
      code
      elementKey
      elementIndex
    }
  }
  colorPattern: metaobjectCreate(metaobject: $colorPattern) {
    metaobject {
      id
      type
      handle
      displayName
      definition {
        id
        type
      }
    }
    userErrors {
      field
      message
      code
      elementKey
      elementIndex
    }
  }
}

mutation StandardLinkedMetafieldValuesAttach(
  $metafields: [MetafieldsSetInput!]!
  $productId: ID!
  $options: [OptionCreateInput!]!
) {
  metafieldsSet(metafields: $metafields) {
    metafields {
      namespace
      key
      type
      value
    }
    userErrors {
      field
      message
      code
      elementIndex
    }
  }
  productOptionsCreate(productId: $productId, options: $options) {
    product {
      id
      options {
        name
        linkedMetafield {
          namespace
          key
        }
        optionValues {
          name
          linkedMetafieldValue
        }
      }
    }
    userErrors {
      field
      message
      code
    }
  }
}

query StandardLinkedMetafieldValuesReadback(
  $productId: ID!
  $materialId: ID!
  $colorPatternId: ID!
) {
  product(id: $productId) {
    id
    material: metafield(namespace: "shopify", key: "material") {
      namespace
      key
      type
      value
      references(first: 10) {
        nodes {
          __typename
          ... on Metaobject {
            id
            type
            displayName
            definition {
              id
              type
            }
          }
        }
      }
    }
    colorPattern: metafield(namespace: "shopify", key: "color-pattern") {
      namespace
      key
      type
      value
      references(first: 10) {
        nodes {
          __typename
          ... on Metaobject {
            id
            type
            displayName
            definition {
              id
              type
            }
          }
        }
      }
    }
    options {
      name
      linkedMetafield {
        namespace
        key
      }
      optionValues {
        name
        linkedMetafieldValue
      }
    }
  }
  material: metaobject(id: $materialId) {
    id
    type
    displayName
    definition {
      id
      type
    }
  }
  colorPattern: metaobject(id: $colorPatternId) {
    id
    type
    displayName
    definition {
      id
      type
    }
  }
}

#graphql
  mutation StandardLinkedMetafieldProductCleanup($input: ProductDeleteInput!) {
    productDelete(input: $input) {
      deletedProductId
      userErrors { field message }
    }
  }

#graphql
  mutation StandardLinkedMetafieldValueCleanup($id: ID!) {
    metaobjectDelete(id: $id) {
      deletedId
      userErrors { field message code elementKey elementIndex }
    }
  }

#graphql
  mutation StandardLinkedMetafieldValueCleanup($id: ID!) {
    metaobjectDelete(id: $id) {
      deletedId
      userErrors { field message code elementKey elementIndex }
    }
  }
